  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  3	import { getValidatedProp } from '@odf/shared/utils';
  4	import classNames from 'classnames';
  5	import * as _ from 'lodash-es';
  6	import {
  7	  FormGroup,
  8	  FormHelperText,
  9	  HelperText,
 10	  HelperTextItem,
 11	  TextInput,
 12	  ValidatedOptions,
 13	} from '@patternfly/react-core';
 14	import { validateConnectionName } from '../../constants';
 15	import { VaultConfig, ThalesConfig } from '../../types';
 16	import { parseURL, isValidEndpoint, isValidName } from './utils';
 17	
 18	export const NameAddrPort: React.FC<NameAddrPortProps> = ({
 19	  className,
 20	  kmsState,
 21	  kmsStateClone,
 22	  updateKmsState,
 23	  canAcceptIP,
 24	}) => {
 25	  const { t } = useCustomTranslation();
 26	
 27	  const setServiceName = (name: string) => {
 28	    kmsStateClone.name.value = name;
 29	    kmsStateClone.name.valid = isValidName(name);
 30	    updateKmsState(kmsStateClone);
 31	  };
 32	
 33	  const setAddress = (address: string) => {
 34	    const trimAddress = address.trim();
 35	    const validAddress: boolean = canAcceptIP
 36	      ? isValidEndpoint(trimAddress)
 37	      : parseURL(trimAddress) != null;
 38	    kmsStateClone.address.value = trimAddress;
 39	    kmsStateClone.address.valid = address !== '' && validAddress;
 40	    updateKmsState(kmsStateClone);
 41	  };
 42	
 43	  const setAddressPort = (port: string) => {
 44	    kmsStateClone.port.value = port;
 45	    kmsStateClone.port.valid =
 46	      port !== '' &&
 47	      !_.isNaN(Number(port)) &&
 48	      Number(port) > 0 &&
 49	      Number(port) < 65536;
 50	    updateKmsState(kmsStateClone);
 51	  };
 52	
 53	  const validateAddressMessage = () =>
 54	    kmsState.address.value === ''
 55	      ? t('This is a required field')
 56	      : canAcceptIP
 57	        ? t('Please enter a valid address')
 58	        : t('Please enter a URL');
 59	
 60	  const validatePortMessage = () =>
 61	    kmsState.port.value === ''
 62	      ? t('This is a required field')
 63	      : t('Please enter a valid port');
 64	
 65	  const getValidatedNameProp = getValidatedProp(!kmsState.name.valid);
 66	  const getValidatedAddressProp = getValidatedProp(!kmsState.address.valid);
 67	  const getValidatedPortProp = getValidatedProp(!kmsState.port.valid);
 68	
 69	  return (
 70	    <>
 71	      <FormGroup
 72	        fieldId="kms-service-name"
 73	        label={t('Connection name')}
 74	        className={`${className}__form-body`}
 75	        isRequired
 76	      >
 77	        <TextInput
 78	          value={kmsState.name.value}
 79	          onChange={(_event, name: string) => setServiceName(name)}
 80	          type="text"
 81	          id="kms-service-name"
 82	          name="kms-service-name"
 83	          isRequired
 84	          validated={getValidatedNameProp}
 85	          data-test="kms-service-name-text"
 86	        />
 87	        <FormHelperText>
 88	          <HelperText>
 89	            <HelperTextItem variant={getValidatedNameProp}>
 90	              {getValidatedNameProp === ValidatedOptions.default
 91	                ? t(
 92	                    'An unique name for the key management service within the project. Name must only include alphanumeric characters, "-", "_" or "."'
 93	                  )
 94	                : validateConnectionName(kmsState.name.value, t)}
 95	            </HelperTextItem>
 96	          </HelperText>
 97	        </FormHelperText>
 98	      </FormGroup>
 99	      <div className="ocs-install-kms__form-url">
100	        <FormGroup
101	          fieldId="kms-address"
102	          label={t('Address')}
103	          className={classNames(
104	            'ocs-install-kms__form-address',
105	            `${className}__form-body`
106	          )}
107	          isRequired
108	        >
109	          <TextInput
110	            value={kmsState.address.value}
111	            onChange={(_event, address: string) => setAddress(address)}
112	            className="ocs-install-kms__form-address--padding"
113	            type="url"
114	            id="kms-address"
115	            name="kms-address"
116	            isRequired
117	            validated={getValidatedAddressProp}
118	            data-test="kms-address-text"
119	          />
120	          <FormHelperText>
121	            <HelperText>
122	              <HelperTextItem variant={getValidatedAddressProp}>
123	                {getValidatedAddressProp === ValidatedOptions.error &&
124	                  validateAddressMessage()}
125	              </HelperTextItem>
126	            </HelperText>
127	          </FormHelperText>
128	        </FormGroup>
129	        <FormGroup
130	          fieldId="kms-address-port"
131	          label={t('Port')}
132	          className={classNames(
133	            'ocs-install-kms__form-port',
134	            `${className}__form-body--small-padding`
135	          )}
136	          isRequired
137	        >
138	          <TextInput
139	            value={kmsState.port.value}
140	            onChange={(_event, port: string) => setAddressPort(port)}
141	            type="text"
142	            id="kms-address-port"
143	            name="kms-address-port"
144	            isRequired
145	            validated={getValidatedPortProp}
146	            data-test="kms-address-port-text"
147	          />
148	          <FormHelperText>
149	            <HelperText>
150	              <HelperTextItem variant={getValidatedPortProp}>
151	                {getValidatedPortProp === ValidatedOptions.error &&
152	                  validatePortMessage()}
153	              </HelperTextItem>
154	            </HelperText>
155	          </FormHelperText>
156	        </FormGroup>
157	      </div>
158	    </>
159	  );
160	};
161	
162	export type NameAddrPortProps = {
163	  kmsState: VaultConfig | ThalesConfig;
164	  className: string;
165	  kmsStateClone: VaultConfig | ThalesConfig;
166	  updateKmsState: (kmsConfig: VaultConfig | ThalesConfig) => void;
167	  canAcceptIP: boolean;
168	};

